public display AmountMST displayShowRemainAmountTransCur()
{
    FormRun formrun;
    AmountMST ShowRemainAmountTransCur, ExchangeRate;
    VendTransOpen                vendTransOpen, vendTransOpenloc;
    ExchangeRateUnionView ExchangeRateUnionView;
    Ledger ledger;
    formrun = this as FormRun;

    if (ETGACFParameters::find().EnableUATSmallPoints == NoYes::No)
    {
        return 0;
    }
    FormDataSource VendTransOpen_ds = formrun.dataSource(formDataSourceStr(VendOpenTrans,VendTransOpen));

    MultiSelectionHelper        selectionHelper = MultiSelectionHelper::construct();

    selectionHelper.parmDataSource(VendTransOpen_ds);
    vendTransOpen = selectionHelper.getFirst();

    //LedgerJournalTrans originator = this.args().record();

    ShowRemainAmountTransCur = 0;
    while select * from vendTransOpenloc where vendTransOpenloc.AccountNum==vendTransOpen.AccountNum
    {
        if (manager.getTransMarked(vendTransOpenloc))
        {

            ShowRemainAmountTransCur += vendTransOpenloc.AmountCur;

        }
    }

    FormRealControl         showTransactionAmountCur =   formRun.design(0).controlName(formControlStr(VendOpenTrans, showTransactionAmountCur));

    return ShowRemainAmountTransCur + showTransactionAmountCur.realValue(); 
}

public display AmountMST displayshowTransactionAmountCur()
{

    FormRun formrun;
    AmountMST showTransactionAmountCur, ExchangeRate,ExchangeRatetotal;
    VendTransOpen               vendTransOpen, vendTransOpenloc;
    ExchangeRateUnionView       ExchangeRateUnionView;
    VendTrans                   vendTransRecord;
    LedgerJournalTrans          originator;
    Ledger                      ledger;
    Common                      record;
    formrun = this as FormRun;

    if (ETGACFParameters::find().EnableUATSmallPoints == NoYes::No)
    {
        return 0;
    }

    FormDataSource VendTransOpen_ds = formrun.dataSource(formDataSourceStr(VendOpenTrans,VendTransOpen));

    MultiSelectionHelper        selectionHelper = MultiSelectionHelper::construct();

    selectionHelper.parmDataSource(VendTransOpen_ds);
    vendTransOpen = selectionHelper.getFirst();

    record = this.args().record();

    //VendTrans vendTransRecord = this.args().record();
   // LedgerJournalTrans originator = LedgerJournalTrans::findByCustVendTrans(vendTransRecord);

    //LedgerJournalTrans originator = this.args().record();

    if (record && record.TableId == tableNum(VendTrans))
    {
        vendTransRecord = record;
        originator = LedgerJournalTrans::findByCustVendTrans(vendTransRecord);
    }
    else if (record && record.TableId == tableNum(LedgerJournalTrans))
    {
        originator = record;
    }

    showTransactionAmountCur = originator.AmountCurDebit - originator.AmountCurCredit;

    ExchangeRatetotal = showTransactionAmountCur;
    while select * from vendTransOpenloc where vendTransOpenloc.AccountNum==vendTransOpen.AccountNum
    {
        //ExchangeRatetotal = 0;
        if (manager.getTransMarked(vendTransOpenloc))
        {
            VendTrans   vendtrans =vendTransOpenloc.vendTrans();
            select firstonly ledger where ledger.Name == curExt();

            select firstonly ExchangeRateUnionView order by ExchangeRateUnionView.ValidFrom desc
            where ExchangeRateUnionView.FromCurrencyCode == originator.CurrencyCode && ExchangeRateUnionView.ToCurrencyCode == vendtrans.CurrencyCode
                && ExchangeRateUnionView.ValidFrom <= originator.TransDate &&  ExchangeRateUnionView.ValidTo >= originator.TransDate
                && ExchangeRateUnionView.ExchangeRateType == ledger.DefaultExchangeRateType;

            ExchangeRate = (ExchangeRateUnionView.ExchangeRate) /100.00;

            if (ExchangeRate > 0)
            {
                ExchangeRatetotal = showTransactionAmountCur * ExchangeRate;
            }

        }
    }


    return ExchangeRatetotal;
    }
